def levenshtein_distance(a, b):
    m = len(a) + 1
    n = len(b) + 1
    d = [[0] * n for _ in range(m)]

    for i in range(m):
        d[i][0] = i
    for j in range(n):
        d[0][j] = j

    for i in range(1, m):
        for j in range(1, n):
            cost = 0 if a[i-1] == b[j-1] else 1
            d[i][j] = min(d[i-1][j] + 1, d[i][j-1] + 1, d[i-1][j-1] + cost)

    return d[m-1][n-1]

def main():
    a = "kitten"
    b = "sitting"
    print(levenshtein_distance(a, b))

if __name__ == "__main__":
    main()
