def f(lst):
    if not lst:
        return 0

    dp = [1] * len(lst)

    for i in range(1, len(lst)):
        for j in range(i):
            if lst[i] > lst[j]:
                dp[i] = max(dp[i], dp[j] + 1)

    return max(dp)
